insert into public.resources (title, description, category, file_url, external_url) values
  ('Co-op Scholar Resume Template', 'A clean, recruiter-approved resume template tailored to Co-op placement applications, with annotated examples.', 'resume', '/resources/coop-resume-template.pdf', null),
  ('Behavioural Interview Question Bank', 'Common behavioural questions asked in Co-op and graduate interviews, with STAR-method answer frameworks.', 'interview', '/resources/interview-question-bank.pdf', null),
  ('UNSW Co-op Program — Official Site', 'The official UNSW Co-op Program page: scholarship details, eligible degrees, and application dates.', 'scholarship', null, 'https://www.coop.unsw.edu.au'),
  ('First Placement Survival Guide', 'Advice from senior scholars on making the most of your first industry placement — expectations, etiquette, and growth.', 'career', '/resources/first-placement-guide.pdf', null),
  ('Scholarship Application Tips', 'How current scholars approached the Co-op application: personal statements, interviews, and assessment days.', 'scholarship', '/resources/scholarship-application-tips.pdf', null),
  ('LinkedIn Profile Checklist', 'A practical checklist for building a professional LinkedIn presence before recruitment season.', 'career', '/resources/linkedin-checklist.pdf', null);
